import React, { useEffect, useRef, useState } from "react";
import Loading from "../LoadingScreen/Loading";
import Layout from "../../components/Layout/Layout";
import Sidebar from "../../components/Sidebar/Sidebar";
import ServerNav from "../../components/ServerNav/ServerNav";

const AppContainer = (props) => {
  const [isLoading, setIsLoading] = useState(true);
  const [directMessages, setDirectMessages] = useState();
  const ws = useRef(null);

  useEffect(() => {
    console.log("APP FETCHING");
    const fetchData = async () => {
      try {
        const res = await fetch("/channel/direct-messages", {
          headers: {
            Authorization: "Bearer " + props.token,
          },
        });

        if (res.status !== 200) {
          throw new Error("An error has occurred.");
        }

        const messagesList = await res.json();
        setDirectMessages(messagesList);
      } catch (err) {
        console.log(err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();

    ws.current = new WebSocket("ws://localhost:8080");

    ws.current.onopen = () => {
      console.log("Connection Opened");
      const data = {
        message: "Hello Server",
        userId: "",
        sender: "",
        users: [],
      };
      ws.current.send(JSON.stringify(data));
    };

    // After sending message to server, client sends back data for update?
    ws.current.onmessage = (message) => {
      console.log(message);
    };

    ws.current.onclose = () => {};
    ws.current.onerror = () => {};

    // Cleanup function
    return () => {
      ws.current.close();
    };
  }, [props.token]);

  const sendMessageHandler = (data) => {
    ws.current.send(JSON.stringify(data));
  };

  if (isLoading) {
    return <Loading></Loading>;
  }

  return (
    <Layout
      nav={<ServerNav />}
      sidebar={
        <Sidebar
          logoutHandler={props.logoutHandler}
          directMessages={directMessages}
        />
      }
    >
      {React.cloneElement(props.children, { ws: ws })}
    </Layout>
  );
};

export default AppContainer;
